import { Hono } from 'hono'
import { basicAuth } from 'hono/basic-auth'
import { prettyJSON } from 'hono/pretty-json'
import api from './api'
import { Bindings } from './bindings'

const app = new Hono()
app.get('/', (c) => c.text('Pretty Blog API'))
app.notFound((c) => c.json({ message: 'Not Found', ok: false }, 404))

const middleware = new Hono<{ Bindings: Bindings }>()
middleware.use('*', prettyJSON())
middleware.use('/posts/*', async (c, next) => {
  if (c.req.method !== 'GET') {
    const auth = basicAuth({ username: c.env.USERNAME, password: c.env.PASSWORD })
    return auth(c, next)
  } else {
    await next()
  }
})

app.route('/api', middleware)
app.route('/api', api)

export default app

apiRoutes.get('/', async (c) => {
  const user = c.get('user')
  if (!user || user.role !== 'admin') {
    return c.json({ error: 'Admin access required' }, 403)
  }

  const db = c.env.DB
  const service = new EventTrackingService(db)

  const filters = {
    event: c.req.query('event') || undefined,
    category: c.req.query('category') || undefined,
    userId: c.req.query('userId') || undefined,
    sessionId: c.req.query('sessionId') || undefined,
    startDate: c.req.query('startDate') ? parseInt(c.req.query('startDate')!) : undefined,
    endDate: c.req.query('endDate') ? parseInt(c.req.query('endDate')!) : undefined,
    limit: c.req.query('limit') ? parseInt(c.req.query('limit')!) : 50,
    offset: c.req.query('offset') ? parseInt(c.req.query('offset')!) : 0
  }

  const result = await service.queryEvents(filters)
  return c.json(result)
})

apiRoutes.get('/events', async (c) => {
  const db = c.env.DB
  const settings = await getSettings(db)
  const service = new SecurityAuditService(db, settings)

  const filters: SecurityEventFilters = {
    eventType: c.req.query('type') as SecurityEventType | undefined,
    severity: c.req.query('severity') as SecuritySeverity | undefined,
    email: c.req.query('email') || undefined,
    ipAddress: c.req.query('ip') || undefined,
    search: c.req.query('search') || undefined,
    startDate: c.req.query('start') ? parseInt(c.req.query('start')!) : undefined,
    endDate: c.req.query('end') ? parseInt(c.req.query('end')!) : undefined,
    page: c.req.query('page') ? parseInt(c.req.query('page')!) : 1,
    limit: c.req.query('limit') ? Math.min(parseInt(c.req.query('limit')!), 100) : 50,
    sortBy: (c.req.query('sortBy') as any) || 'created_at',
    sortOrder: (c.req.query('sortOrder') as any) || 'desc'
  }

  const result = await service.getEvents(filters)
  return c.json(result)
})

apiRoutes.get('/events', requireAuth(), async (c) => {
  const user = c.get('user')
  if (user?.role !== 'admin') return c.json({ error: 'Access denied' }, 403)

  const db = c.env.DB
  const eventService = new StripeEventService(db)
  await eventService.ensureTable()

  const filters = {
    type: c.req.query('type') || undefined,
    status: c.req.query('status') as any || undefined,
    objectId: c.req.query('objectId') || undefined,
    page: c.req.query('page') ? parseInt(c.req.query('page')!) : 1,
    limit: c.req.query('limit') ? parseInt(c.req.query('limit')!) : 50
  }

  const [result, stats, types] = await Promise.all([
    eventService.list(filters),
    eventService.getStats(),
    eventService.getDistinctTypes()
  ])

  return c.json({ ...result, stats, types })
})

admin.get('/:id/edit', async (c: any) => {
  try {
    const id = c.req.param('id')
    const db = c.env?.DB || c.get('db')
    if (!db) {
      return c.html('<h1>Database not available</h1>', 500)
    }

    const ref = c.req.query('ref') || undefined
    const service = new RedirectService(db)
    const redirect = await service.getById(id)

    if (!redirect) {
      return c.redirect('/admin/redirects', 303)
    }

    const html = renderRedirectFormPage({
      isEdit: true,
      redirect,
      referrerParams: ref,
      user: c.get('user')
    })
    return c.html(html)
  } catch (error) {
    console.error('Error loading edit form:', error)
    return c.html('<h1>Error loading form</h1>', 500)
  }
})

adminCollectionsRoutes.post('/:collectionId/fields/reorder', async (c) => {
  try {
    const body = await c.req.json()
    const fieldIds = body.fieldIds as string[]

    if (!Array.isArray(fieldIds)) {
      return c.json({ success: false, error: 'Invalid field order data.' })
    }

    const db = c.env.DB

    // Update field order
    for (let i = 0; i < fieldIds.length; i++) {
      const updateStmt = db.prepare('UPDATE content_fields SET field_order = ?, updated_at = ? WHERE id = ?')
      await updateStmt.bind(i + 1, Date.now(), fieldIds[i]).run()
    }

    return c.json({ success: true })
  } catch (error) {
    console.error('Error reordering fields:', error)
    return c.json({ success: false, error: 'Failed to reorder fields.' })
  }
})

if (token) {
  const apiKeyResult = await verifyApiKey(token);
  if (apiKeyResult?.valid && apiKeyResult.key) {
    const key = apiKeyResult.key;
    c.set("userId", key.userId);
    c.set("userEmail", "");
    c.set("user", null);
    c.set("session", null);
    c.set("apiKey", {
      id: key.id,
      userId: key.userId,
      enabled: key.enabled,
    });
    return;
  }
  const sessionResult = await getSessionFromBearerOnlyHeaders(c);
  if (sessionResult?.user && sessionResult.session) {
    c.set("user", sessionResult.user);
    c.set("session", sessionResult.session);
    c.set("userId", sessionResult.user.id);
    c.set("userEmail", sessionResult.user.email ?? "");
    return;
  }
  throw new HTTPException(401, { message: "Unauthorized" });
}

const badRequestResponse = (
  c: Context,
  message: string,
  details?: string,
  meta?: Record<string, unknown>,
  source?: { pointer?: string; parameter?: string; header?: string },
) => {
  const url = new URL(c.req.url);
  c.status(400);
  return c.json<z.infer<typeof ErrorResponseSchema>, 400>({
    errors: [
      {
        status: 400,
        code: 'BAD_REQUEST',
        title: message,
        details: details ?? 'There was an error while processing the request',
        meta: meta ?? {},
        source: source ?? {},
        links: {
          about: `https://${url.origin}/docs/errors/BAD_REQUEST`,
          type: `https://${url.origin}/docs/errors`,
        },
      },
    ],
  });
};

const except = (
  condition: string | Condition | (string | Condition)[],
  ...middleware: MiddlewareHandler[]
): MiddlewareHandler => {
  let router: TrieRouter<true> | undefined = undefined
  const conditions = (Array.isArray(condition) ? condition : [condition])
    .map((condition) => {
      if (typeof condition === 'string') {
        router ||= new TrieRouter()
        router.add(METHOD_NAME_ALL, condition, true)
      } else {
        return condition
      }
    })
    .filter(Boolean) as Condition[]

  if (router) {
    conditions.unshift((c: Context) => !!router?.match(METHOD_NAME_ALL, c.req.path)?.[0]?.[0]?.[0])
  }

  const handler = some((c: Context) => conditions.some((cond) => cond(c)), every(...middleware))
  return async function except(c, next) {
    await handler(c, next)
  }
}

route<
    SubPath extends string,
    SubEnv extends Env,
    SubSchema extends Schema,
    SubBasePath extends string,
    SubCurrentPath extends string,
  >(
    path: SubPath,
    app: Hono<SubEnv, SubSchema, SubBasePath, SubCurrentPath>
  ): Hono<E, MergeSchemaPath<SubSchema, MergePath<BasePath, SubPath>> | S, BasePath, CurrentPath> {
    const subApp = this.basePath(path)
    app.routes.map((r) => {
      let handler
      if (app.errorHandler === errorHandler) {
        handler = r.handler
      } else {
        handler = async (c: Context, next: Next) =>
          (await compose([], app.errorHandler)(c, () => r.handler(c, next))).res
        ;(handler as any)[COMPOSED_HANDLER] = r.handler
      }

      subApp.#addRoute(r.method, r.path, handler, r.basePath)
    })
    return this
  }

const memo = <T>(
  component: FC<T>,
  propsAreEqual: (prevProps: Readonly<T>, nextProps: Readonly<T>) => boolean = shallowEqual
): FC<T> => {
  let computed: ReturnType<FC<T>> = null
  let prevProps: T | undefined = undefined
  const wrapper: MemorableFC<T> = ((props: T) => {
    if (prevProps && !propsAreEqual(prevProps, props)) {
      computed = null
    }
    prevProps = props
    return (computed ||= component(props))
  }) as MemorableFC<T>

  // This function is for toString(), but it can also be used for DOM renderer.
  // So, set DOM_MEMO and DOM_RENDERER for DOM renderer.
  wrapper[DOM_MEMO] = propsAreEqual
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ;(wrapper as any)[DOM_RENDERER] = component

  return wrapper as FC<T>
}

const healthServer = createServer((req, res) => {
  if (req.url?.startsWith('/health')) {
    const version = process.env.RELEASE_SHA ?? 'unknown';
    const url = new URL(req.url, `http://localhost:${env.CDC_HEALTH_PORT}`);
    if (url.searchParams.get('depth') === 'full') {
      const { response, httpStatus } = getHealthResponse();
      res.writeHead(httpStatus, {
        'Content-Type': 'application/json',
        'Cache-Control': 'public, max-age=5',
        'X-App-Version': version,
      });
      res.end(JSON.stringify({ ...response, version }));
      return;
    }
    res.writeHead(204, { 'Cache-Control': 'public, max-age=5', 'X-App-Version': version });
    res.end();
    return;
  }
  res.writeHead(404);
  res.end();
});
